  font-size: 0.6875rem;
  font-weight: 700;
  letter-spacing: 0.01em;
  white-space: nowrap;
}

.visa-featured-signal svg {
  width: 0.875rem;
  height: 0.875rem;
}

.visa-featured-copy {
  display: grid;
  min-width: 0;
  gap: var(--space-3xs);
}

.visa-featured-copy h3 {
  color: var(--text-primary);
  font-family: var(--font-display);
  font-size: clamp(1.0625rem, 0.8vw + 0.9rem, 1.25rem);
  font-style: normal;
  font-weight: 700;
  letter-spacing: -0.025em;
  line-height: 1.25;
}

.visa-featured-location {
  display: inline-flex;
  min-width: 0;
  align-items: center;
  gap: var(--space-3xs);
  color: var(--text-muted);
  font-size: 0.8125rem;
  line-height: 1.5;
}

.visa-featured-location svg {
  flex: 0 0 auto;
  width: 0.9375rem;
  height: 0.9375rem;
}

.visa-featured-location span {
  min-width: 0;
  overflow-wrap: anywhere;
}

.visa-featured-count {
  display: grid;
  gap: var(--space-3xs);
  min-width: 0;
  padding: var(--space-xs) var(--space-sm);
  border-radius: var(--radius-input);
  background: var(--color-paper-2);
  border: var(--rule-width) solid var(--border-subtle);
}

.visa-featured-count strong {
  color: var(--text-primary);
  font-family: var(--font-display);
  font-size: 1.5rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
}

.visa-featured-count span {
  color: var(--text-secondary);
  font-size: 0.75rem;
  font-weight: 600;
  line-height: 1.4;
}

.visa-featured-actions {
  display: grid;
  gap: var(--space-2xs);
  margin-top: auto;
}

.visa-featured-primary {
  width: 100%;
  padding-inline: var(--space-md);
  background: var(--accent-primary);
  color: var(--text-on-accent);
  box-shadow: var(--shadow-button);
  transition:
    background-color var(--dur-short) var(--ease-out),
    transform 100ms var(--ease-out),
    box-shadow 100ms var(--ease-out);
}

.visa-featured-primary:active {
  box-shadow: var(--shadow-button-pressed);
}

.visa-featured-secondary {
  width: 100%;
  padding-inline: var(--space-md);
  border: var(--rule-width) solid var(--border-subtle);
  background: var(--color-paper);
  color: var(--text-primary);
  transition:
    background-color var(--dur-short) var(--ease-out),
    border-color var(--dur-short) var(--ease-out);
}

.visa-results-minimal-empty {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-xs);
  padding-block: var(--space-xs);
  border-block: var(--rule-width) solid var(--border-subtle);
  color: var(--text-secondary);
  font-size: 0.8125rem;
}

.visa-results-minimal-empty a {
  min-height: 2.75rem;
  display: inline-flex;
  align-items: center;
  color: var(--text-primary);
  font-weight: 700;
  white-space: nowrap;
}

.visa-results-state {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  gap: var(--space-sm);
  align-items: center;
  padding: var(--space-md);
  border: var(--rule-width) solid var(--color-rule);
  border-radius: var(--radius-card);
  background: var(--color-paper);
  color: var(--text-primary);
  box-shadow: var(--shadow-card);
}

.visa-results-state h3 {
  font-family: var(--font-display);
  font-size: 1rem;
  font-style: normal;
  font-weight: 700;
}

.visa-results-state p {
  margin-top: var(--space-3xs);
  color: var(--text-secondary);
  font-size: 0.8125rem;
  line-height: 1.6;
}

.visa-results-state-action {
  grid-column: 1 / -1;
  display: inline-flex;
  width: fit-content;
  min-height: 2.75rem;
  align-items: center;
  justify-content: center;
  padding-inline: var(--space-md);
  white-space: nowrap;
  font-size: 0.875rem;
  font-weight: 700;
  cursor: pointer;
}

.visa-featured-skeleton {
  min-height: 14rem;
  box-shadow: none;
}

.visa-featured-skeleton span {
  display: block;
  height: 0.75rem;
  border-radius: var(--radius-pill);
  background: var(--color-paper-3);
  animation: visa-featured-loading 1.2s var(--ease-snap) infinite alternate;
}

.visa-featured-skeleton span:nth-child(1) {
  width: 2.75rem;
  height: 2.75rem;
  border-radius: var(--radius-input);
}

.visa-featured-skeleton span:nth-child(2) {
  width: 68%;
}

.visa-featured-skeleton span:nth-child(3) {
  width: 42%;
  height: 3rem;
  border-radius: var(--radius-input);
}

.visa-featured-skeleton span:nth-child(4) {
  width: 100%;
  height: 2.75rem;
  border-radius: var(--radius-button);
}

@keyframes visa-featured-loading {
  from {
    opacity: 0.45;
  }
  to {
    opacity: 1;
  }
}

@media (hover: hover) and (pointer: fine) {
  .visa-results-board-link:hover {
    border-color: var(--color-rule);
    background: var(--color-paper-2);
  }

  .visa-featured-card:hover {
    border-color: var(--color-rule);
    background: var(--color-paper);
    box-shadow: var(--shadow-card);
    transform: translateY(-2px);
  }

  .visa-featured-primary:hover {
    background: var(--accent-primary-hover);
    box-shadow: var(--shadow-button-hover);
  }

  .visa-featured-secondary:hover {
    border-color: var(--color-rule);
    background: var(--color-paper-2);
  }
}

@media (min-width: 40rem) {
  .visa-results-head {
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .visa-featured-list {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }

  .visa-results-state {
    grid-template-columns: auto minmax(0, 1fr) auto;
  }

  .visa-results-state-action {
    grid-column: auto;
  }
}

.visa-featured-skeleton span {
  animation: none;
  opacity: 0.7;
}

.visa-results-board-link,
.visa-featured-card,
.visa-featured-primary,
.visa-featured-secondary,
.visa-results-state-action {
  transition: none;
}

.visa-results-board-link:active,
.visa-featured-primary:active,
.visa-featured-secondary:active,
.visa-results-minimal-empty a:active,
.visa-results-state-action:active {
  transform: none;
}

.visa-featured-card:hover {
  transform: none;
}

input.old_string:
.visa-role-skeleton span {
  animation: none;
  opacity: 0.7;
}

.visa-results-board-link,
.visa-role-action,
.visa-featured-company,
.visa-results-state-action {
  transition: none;
}

.visa-results-board-link:active,
.visa-role-action:active,
.visa-featured-company:active,
.visa-results-minimal-empty a:active,
.visa-results-state-action:active {
  transform: none;
}
